class Solution {
public:
    vector<vector<int>> strongConnect(vector<vector<int>>& g) {
        vector<bool> visited(g.size(), false);
        vector<vector<int>> sccs;
        stack<int> stk;
        for (int node = 0; node < g.size(); node++) {
            if (!visited[node]) {
                dfs(node, visited, g, stk);
            }
        }
        while (!stk.empty()) {
            int node = stk.top(); stk.pop();
            visited[node] = true;
            for (int neighbor : g[node]) {
                if (!visited[neighbor]) {
                    dfs(neighbor, visited, g, stk);
                }
            }
            sccs.push_back({node});
        }
        return sccs;
    }

    void dfs(int node, vector<bool>& visited, vector<vector<int>>& g, stack<int>& stk) {
        if (visited[node]) return;
        visited[node] = true;
        stk.push(node);
        for (int neighbor : g[node]) {
            if (!visited[neighbor]) {
                dfs(neighbor, visited, g, stk);
            }
        }
    }
};

