public class Solution {
public List<List<Integer>> strongConnect(List<List<Integer>> g) {
    int n = g.size();
    List<Boolean> visited = new ArrayList<>(Collections.nCopies(n, false));
    List<List<Integer>> sccs = new ArrayList<>();
    Stack<Integer> stk = new Stack<>();
    for (int node = 0; node < n; node++) {
        if (!visited.get(node)) {
            dfs(node, visited, g, stk);
        }
    }
    while (!stk.isEmpty()) {
        int node = stk.pop();
        visited.set(node, true);
        for (int neighbor : g.get(node)) {
            if (!visited.get(neighbor)) {
                dfs(neighbor, visited, g, stk);
            }
        }
        sccs.add(List.of(node));
    }
    return sccs;
}

private void dfs(int node, List<Boolean> visited, List<List<Integer>> g, Stack<Integer> stk) {
    if (visited.get(node)) return;
    visited.set(node, true);
    stk.push(node);
    for (int neighbor : g.get(node)) {
        if (!visited.get(neighbor)) {
            dfs(neighbor, visited, g, stk);
        }
    }
}

