class Solution:
    def strongConnect(self, g:
        n = len(g)
        visited = [False] * n
        sccs = []
        stk = []
        for node in range(n):
            if not visited[node]:
                self.dfs(node, visited, g, stk)
        while stk:
            node = stk.pop()
            visited[node] = True
            for neighbor in g[node]:
                if not visited[neighbor]:
                    self.dfs(neighbor, visited, g, stk)
            sccs.append([node])

        return sccs

    def dfs(self, node, visited, g, stk) -> None:
        if visited[node]: return
        visited[node] = True
        stk.append(node)
        for neighbor in g[node]:
            if not visited[neighbor]:
                self.dfs(neighbor, visited, g, stk)
